**CARD RENDERING** — Use this JS function to render any card as SVG. Call `renderCard('A', '♠')` for Ace of Spades, etc. Face cards get geometric portraits.
```js
function renderCard(rank, suit) {
  const isRed = suit === '♥' || suit === '♦';
  const color = isRed ? '#dc2626' : '#1a1a2e';
  const bg = '#fefef8';
  let faceArt = '';
  if (['J','Q','K'].includes(rank)) {
    const crown = rank === 'K' ? '<polygon points="30,25 35,15 40,22 45,12 50,22 55,15 60,25" fill="#d4a017" stroke="#8b6914" stroke-width="1"/>' : '';
    const face = rank === 'Q' ? '<circle cx="45" cy="42" r="12" fill="none" stroke="'+color+'" stroke-width="2"/><circle cx="41" cy="39" r="1.5" fill="'+color+'"/><circle cx="49" cy="39" r="1.5" fill="'+color+'"/><path d="M41,46 Q45,50 49,46" fill="none" stroke="'+color+'" stroke-width="1.5"/><path d="M33,30 Q30,42 36,50" fill="none" stroke="'+color+'" stroke-width="1.5"/><path d="M57,30 Q60,42 54,50" fill="none" stroke="'+color+'" stroke-width="1.5"/>' : '<circle cx="45" cy="42" r="12" fill="none" stroke="'+color+'" stroke-width="2"/><circle cx="41" cy="39" r="1.5" fill="'+color+'"/><circle cx="49" cy="39" r="1.5" fill="'+color+'"/><line x1="42" y1="46" x2="48" y2="46" stroke="'+color+'" stroke-width="1.5"/>';
    faceArt = '<rect x="25" y="20" width="40" height="44" rx="4" fill="'+bg+'" stroke="'+color+'" stroke-width="1.5"/>' + crown + face;
  }
  const pips = rank === 'A' ? '<text x="45" y="55" font-size="28" text-anchor="middle" fill="'+color+'">'+suit+'</text>' : '';
  return `<svg viewBox="0 0 90 126" xmlns="http://www.w3.org/2000/svg"><rect width="90" height="126" rx="8" fill="${bg}" stroke="#ccc" stroke-width="1"/><text x="8" y="20" font-size="16" font-weight="bold" fill="${color}">${rank}</text><text x="8" y="36" font-size="14" fill="${color}">${suit}</text><text x="82" y="118" font-size="16" font-weight="bold" fill="${color}" text-anchor="end" transform="rotate(180,82,112)">${rank}</text><text x="82" y="102" font-size="14" fill="${color}" text-anchor="end" transform="rotate(180,82,96)">${suit}</text>${faceArt}${pips}</svg>`;
}
```

